import{_ as t,o as a,c as s,d as e}from"./app-wf1GJAsU.js";const i="/assets/1730277707345-BcuZ335Y.png",o="/assets/1730277854282-CvbIWFL6.png",n="/assets/1730277954156-D4syc4No.png",c="/assets/1730278081543-Bqz4zdxC.png",p="/assets/1730278149141-D7AYxO6m.png",r="/assets/1730278252048-BtZDd1A0.png",m="/assets/1730278630519-BgquDw7B.png",l="/assets/1730278675906-CIIrbTu3.png",d={},h=e('<h1 id="前言" tabindex="-1"><a class="header-anchor" href="#前言"><span>前言</span></a></h1><p>在Linux011操作系统实验教程中让学生使用vi编辑器写代码和修改部分文件的操作，相信有些同学深受其害(vim大佬别来杠)，下面介绍一种可以在本地编写完所有的文件然后传入Linux011操作系统中方法</p><h1 id="第一步-在本地编写好要导入的文件" tabindex="-1"><a class="header-anchor" href="#第一步-在本地编写好要导入的文件"><span>第一步，在本地编写好要导入的文件</span></a></h1><p>下面我的为了方便演示，就将要导入的文件放在项目里面。 <img src="'+i+'" alt="1730277707345"></p><h1 id="第二步-在-终端-运行生成任务-里选择-打开-floppyb-img" tabindex="-1"><a class="header-anchor" href="#第二步-在-终端-运行生成任务-里选择-打开-floppyb-img"><span>第二步，在&quot;终端&quot;--&gt;&quot;运行生成任务...&quot;里选择&quot;打开 floppyb.img&quot;</span></a></h1><p><img src="'+o+'" alt="1730277854282"></p><h1 id="第三步-将要导入的文件复制到floppyb-img文件中" tabindex="-1"><a class="header-anchor" href="#第三步-将要导入的文件复制到floppyb-img文件中"><span>第三步，将要导入的文件复制到floppyb.img文件中</span></a></h1><p><img src="'+n+'" alt="1730277954156"> 如果显示已存在，当然要选择覆盖 <img src="'+c+'" alt="1730278081543"> 可以在floppyb.img文件中双击我们要更改的文件，再次确认一下：（确定复制成功了） <img src="'+p+'" alt="1730278149141"></p><h1 id="第四步-在bochs虚拟机中运行linux" tabindex="-1"><a class="header-anchor" href="#第四步-在bochs虚拟机中运行linux"><span>第四步，在Bochs虚拟机中运行Linux</span></a></h1><p>还是刚才的&quot;终端&quot;--&gt;&quot;运行生成任务...&quot;里面 <img src="'+r+'" alt="1730278252048"></p><h1 id="第五步-导入" tabindex="-1"><a class="header-anchor" href="#第五步-导入"><span>第五步，导入！</span></a></h1><p>首先要切换到你要导入的linux系统中的路径，我这里直接在这儿导入了 然后执行一下命令：（mcopy b:&lt;你保存到floppyb.img文件中的文件名(转化成小写)&gt; &lt;要保存成的文件名&gt;） 命令中的b代表的是floppyb.img文件，如果已经存在记得覆盖（输入y即可） <img src="'+m+'" alt="1730278630519"> 可以验证得知，成功导入： <img src="'+l+'" alt="1730278675906"></p><h1 id="结语" tabindex="-1"><a class="header-anchor" href="#结语"><span>结语</span></a></h1><p>这种方法我觉得仅适用于不想在这个老古董上面写东西的同学，但是vi和vim编辑器的使用方法还是需要掌握的。 （但是这样就能让AI检查你的代码了）（bushi）</p>',14),g=[h];function u(_,f){return a(),s("div",null,g)}const x=t(d,[["render",u],["__file","index.html.vue"]]),y=JSON.parse(`{"path":"/article/82o3klmd/","title":"Linux011操作系统实验vi编辑器逃课教程()","lang":"zh-CN","frontmatter":{"title":"Linux011操作系统实验vi编辑器逃课教程()","createTime":"2024/10/30 11:45:14","author":"only9464","tags":["Linux","vi","vim","操作系统"],"permalink":"/article/82o3klmd/","head":[["script",{"id":"check-dark-mode"},";(function () {const um= localStorage.getItem('vuepress-theme-appearance') || 'auto';const sm = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches;if (um === 'dark' || (um !== 'light' && sm)) {document.documentElement.classList.add('dark');}})();"],["script",{"id":"check-mac-os"},"document.documentElement.classList.toggle('mac', /Mac|iPhone|iPod|iPad/i.test(navigator.platform))"]]},"headers":[],"isBlogPost":true,"readingTime":{"minutes":1.9,"words":569},"git":{"updatedTime":1730279309000,"contributors":[{"name":"only9464","email":"sky9464@qq.com","commits":1}]},"filePathRelative":"blog/Linux011操作系统实验vi编辑器逃课教程.md","categoryList":[{"type":10000,"name":"blog"}]}`);export{x as comp,y as data};
